const regs = msg.payload;
const faultTexts = {
    0:'No Fault', 2:'F002: Overcurrent', 3:'F003: DC Overvoltage',
    4:'F004: IGBT Overtemp', 5:'F005: Motor Overload', 6:'F006: Drive Overtemp',
    7:'F007: Overcurrent Ph-U', 8:'F008: Overcurrent Ph-V', 9:'F009: Overcurrent Ph-W',
    12:'F012: Phase Loss Input', 21:'F021: Earth Fault', 22:'F022: Motor Overtemp PTC',
    33:'F033: Undervoltage', 49:'F049: Motor Stalled',
    70:'F070: Comm Error', 72:'F072: Fieldbus Timeout', 74:'F074: Serial Error'
};

const devices = [];
for (let i = 0; i < 4; i++) {
    const b = i * 10;
    const sw = regs[b];
    const fc = regs[b + 6];
    devices.push({
        name: 'CFW900 #' + (i+1),
        statusWord: sw,
        speedRPM: regs[b+1],
        current: regs[b+2] / 10.0,
        frequency: regs[b+3] / 10.0,
        dcBusVoltage: regs[b+4] / 10.0,
        torque: regs[b+5] / 10.0,
        faultCode: fc,
        faultText: faultTexts[fc] || ('Fault: ' + fc),
        online: regs[b+7] === 1,
        commErrors: regs[b+8],
        ready:   (sw & 0x0001) !== 0,
        running: (sw & 0x0002) !== 0,
        fault:   (sw & 0x0008) !== 0,
        warning: (sw & 0x0080) !== 0,
        statusText: (sw & 0x0008) ? 'FAULT' : (sw & 0x0002) ? 'RUNNING' : (sw & 0x0001) ? 'READY' : 'OFF',
        statusColor: (sw & 0x0008) ? '#DC0000' : (sw & 0x0002) ? '#0064DC' : (sw & 0x0001) ? '#00B400' : '#808080'
    });
}

flow.set('cfwDevices', devices);
msg.cfwDevices = devices;
return msg;

const regs = msg.payload;
const faultTexts = {
    0:'No Fault', 1:'F01: Motor Overcurrent', 2:'F02: Phase Sequence',
    3:'F03: Phase Loss Input', 4:'F04: Phase Loss Output', 5:'F05: Thyristor Short',
    6:'F06: Heatsink Overtemp', 7:'F07: Motor Overload', 8:'F08: Undervoltage',
    9:'F09: Overvoltage', 10:'F10: Phase Imbalance', 11:'F11: Motor PTC Overtemp',
    20:'F20: Bypass Contactor', 30:'F30: Comm Error',
    51:'F51: Locked Rotor', 73:'F73: Serial Timeout'
};

const devices = [];
for (let i = 0; i < 4; i++) {
    const b = i * 10;
    const sw = regs[b];
    const fc = regs[b + 4];
    devices.push({
        name: 'SSW900 #' + (i+1),
        statusWord: sw,
        current: regs[b+1] / 10.0,
        voltage: regs[b+2] / 10.0,
        power: regs[b+3] / 10.0,
        faultCode: fc,
        faultText: faultTexts[fc] || ('Fault: ' + fc),
        online: regs[b+5] === 1,
        commErrors: regs[b+6],
        ready:    (sw & 0x0001) !== 0,
        running:  (sw & 0x0002) !== 0,
        starting: (sw & 0x0004) !== 0,
        fault:    (sw & 0x0008) !== 0,
        statusText: (sw & 0x0008) ? 'FAULT' : (sw & 0x0002) ? 'RUNNING' : (sw & 0x0004) ? 'STARTING' : (sw & 0x0001) ? 'READY' : 'OFF',
        statusColor: (sw & 0x0008) ? '#DC0000' : (sw & 0x0002) ? '#0064DC' : (sw & 0x0004) ? '#C8C800' : (sw & 0x0001) ? '#00B400' : '#808080'
    });
}

flow.set('sswDevices', devices);
msg.sswDevices = devices;
return msg;

const cfwDevices = flow.get('cfwDevices') || [];
const sswDevices = flow.get('sswDevices') || [];

// Build alarm banner
const faults = [];
cfwDevices.forEach(d => {
    if (d.fault) faults.push(d.name + ': ' + d.faultText);
    else if (!d.online && d.commErrors > 5) faults.push(d.name + ': COMM LOST');
});
sswDevices.forEach(d => {
    if (d.fault) faults.push(d.name + ': ' + d.faultText);
    else if (!d.online && d.commErrors > 5) faults.push(d.name + ': COMM LOST');
});

let banner;
if (faults.length === 0) {
    banner = { text: 'SYSTEM OK - All drives operating normally', color: '#00B400', hasFaults: false, faultCount: 0 };
} else {
    const idx = (flow.get('bannerIdx') || 0) % faults.length;
    flow.set('bannerIdx', idx + 1);
    banner = { text: '[' + (idx+1) + '/' + faults.length + '] ' + faults[idx], color: '#DC0000', hasFaults: true, faultCount: faults.length };
}

msg.cfwDevices = cfwDevices;
msg.sswDevices = sswDevices;
msg.banner = banner;
return msg;

const d = flow.get('cfwDevices') || [];
if (d.length < 4) return null;

return [
    {payload: d[0].current, topic: 'CFW#1'},
    {payload: d[1].current, topic: 'CFW#2'},
    {payload: d[2].current, topic: 'CFW#3'},
    {payload: d[3].current, topic: 'CFW#4'},
    {payload: d[0].dcBusVoltage, topic: 'CFW#1'},
    {payload: d[1].dcBusVoltage, topic: 'CFW#2'},
    {payload: d[2].dcBusVoltage, topic: 'CFW#3'},
    {payload: d[3].dcBusVoltage, topic: 'CFW#4'}
];

const d = flow.get('sswDevices') || [];
if (d.length < 4) return null;

return [
    {payload: d[0].current, topic: 'SSW#1'},
    {payload: d[1].current, topic: 'SSW#2'},
    {payload: d[2].current, topic: 'SSW#3'},
    {payload: d[3].current, topic: 'SSW#4'},
    {payload: d[0].voltage, topic: 'SSW#1'},
    {payload: d[1].voltage, topic: 'SSW#2'},
    {payload: d[2].voltage, topic: 'SSW#3'},
    {payload: d[3].voltage, topic: 'SSW#4'}
];

const cfwDevices = flow.get('cfwDevices') || [];
const sswDevices = flow.get('sswDevices') || [];
const prevFaults = flow.get('activeFaults') || {};
const currentFaults = {};
const newAlarms = [];
const clearedAlarms = [];

cfwDevices.forEach((d, i) => {
    const key = 'CFW_' + (i+1);
    if (d.fault) {
        currentFaults[key] = {device:d.name, type:'FAULT', text:d.faultText, current:d.current, voltage:d.dcBusVoltage};
        if (!prevFaults[key]) newAlarms.push(currentFaults[key]);
    } else if (!d.online && d.commErrors > 5) {
        currentFaults[key] = {device:d.name, type:'COMM_LOST', text:'Communication Lost'};
        if (!prevFaults[key]) newAlarms.push(currentFaults[key]);
    }
    if (d.dcBusVoltage > 750 || (d.dcBusVoltage < 350 && d.dcBusVoltage > 0)) {
        const vk = 'CFW_V_' + (i+1);
        currentFaults[vk] = {device:d.name, type:'VOLTAGE', text: d.dcBusVoltage>750?'DC OVERVOLTAGE':'DC UNDERVOLTAGE', voltage:d.dcBusVoltage};
        if (!prevFaults[vk]) newAlarms.push(currentFaults[vk]);
    }
});

sswDevices.forEach((d, i) => {
    const key = 'SSW_' + (i+1);
    if (d.fault) {
        currentFaults[key] = {device:d.name, type:'FAULT', text:d.faultText, current:d.current, voltage:d.voltage};
        if (!prevFaults[key]) newAlarms.push(currentFaults[key]);
    } else if (!d.online && d.commErrors > 5) {
        currentFaults[key] = {device:d.name, type:'COMM_LOST', text:'Communication Lost'};
        if (!prevFaults[key]) newAlarms.push(currentFaults[key]);
    }
});

Object.keys(prevFaults).forEach(k => {
    if (!currentFaults[k]) clearedAlarms.push(prevFaults[k]);
});

flow.set('activeFaults', currentFaults);

const msgs = [];
if (newAlarms.length > 0) msgs.push({type:'alarm', alarms:newAlarms});
if (clearedAlarms.length > 0) msgs.push({type:'clear', alarms:clearedAlarms});

if (msgs.length > 0) {
    msg.notifications = msgs;
    return msg;
}
return null;

const COOLDOWN = 5*60*1000;
const lastSent = flow.get('notifCooldown') || {};
const now = Date.now();
const filtered = [];

msg.notifications.forEach(n => {
    const fa = n.alarms.filter(a => {
        const k = a.device + '_' + a.type;
        if (n.type === 'clear') return true;
        if (lastSent[k] && (now - lastSent[k]) < COOLDOWN) return false;
        lastSent[k] = now;
        return true;
    });
    if (fa.length > 0) filtered.push({type:n.type, alarms:fa});
});

flow.set('notifCooldown', lastSent);
if (filtered.length > 0) {
    msg.notifications = filtered;
    return msg;
}
return null;

const n = msg.notifications || [];
const now = new Date().toLocaleString();
let lines = [];

n.forEach(notif => {
    if (notif.type === 'alarm') {
        lines.push('🚨 *WEG ALARM*');
        lines.push('📅 ' + now);
        lines.push('');
        notif.alarms.forEach(a => {
            lines.push('🔴 *' + a.device + '*');
            lines.push('   ' + a.type + ': ' + a.text);
            if (a.voltage) lines.push('   ⚡ Voltage: ' + a.voltage + ' V');
            if (a.current) lines.push('   Current: ' + a.current + ' A');
            lines.push('');
        });
    } else {
        lines.push('✅ *ALARM CLEARED*');
        lines.push('📅 ' + now);
        notif.alarms.forEach(a => {
            lines.push('🟢 *' + a.device + '* → CLEARED');
        });
    }
});

msg.payload = {
    chatId: flow.get('telegramChatId') || 0,
    type: 'message',
    content: lines.join('\n'),
    options: { parse_mode: 'Markdown' }
};
return msg;

const n = msg.notifications || [];
const now = new Date().toLocaleString();
let subject = '';
let body = '';

n.forEach(notif => {
    if (notif.type === 'alarm') {
        subject = '🚨 WEG ALARM: ' + notif.alarms.map(a=>a.device).join(', ');
        body = '<h2 style="color:red">WEG Drive Alarm - ' + now + '</h2><table border="1" cellpadding="8"><tr><th>Device</th><th>Type</th><th>Detail</th><th style="color:goldenrod">Voltage</th><th>Current</th></tr>';
        notif.alarms.forEach(a => {
            body += '<tr><td><b>' + a.device + '</b></td><td>' + a.type + '</td><td>' + a.text + '</td><td style="color:goldenrod;font-weight:bold">' + (a.voltage||'-') + ' V</td><td>' + (a.current||'-') + ' A</td></tr>';
        });
        body += '</table>';
    } else {
        subject = '✅ WEG CLEARED: ' + notif.alarms.map(a=>a.device).join(', ');
        body = '<h2 style="color:green">Alarm Cleared - ' + now + '</h2><ul>';
        notif.alarms.forEach(a => { body += '<li><b>' + a.device + '</b> → CLEARED</li>'; });
        body += '</ul>';
    }
});

msg.topic = subject;
msg.payload = body;
return msg;

const cfw = flow.get('cfwDevices') || [];
const ssw = flow.get('sswDevices') || [];
let vs = flow.get('vStats') || {cfw:[{},{},{},{}], ssw:[{},{},{},{}]};

const cfwV = [], sswV = [];

cfw.forEach((d,i) => {
    if (!vs.cfw[i].min) vs.cfw[i] = {min:9999,max:0,sum:0,cnt:0};
    const v = d.dcBusVoltage;
    if (v > 0 && d.online) {
        vs.cfw[i].min = Math.min(vs.cfw[i].min, v);
        vs.cfw[i].max = Math.max(vs.cfw[i].max, v);
        vs.cfw[i].sum += v; vs.cfw[i].cnt++;
    }
    cfwV.push({name:d.name, now:v, min:vs.cfw[i].cnt>0?vs.cfw[i].min:0, max:vs.cfw[i].max, avg:vs.cfw[i].cnt>0?(vs.cfw[i].sum/vs.cfw[i].cnt).toFixed(1):0, alarm:v>750||(v<350&&v>0)});
});

let sSum=0, sOn=0;
ssw.forEach((d,i) => {
    if (!vs.ssw[i].min) vs.ssw[i] = {min:9999,max:0,sum:0,cnt:0};
    const v = d.voltage;
    if (v > 0 && d.online) {
        vs.ssw[i].min = Math.min(vs.ssw[i].min, v);
        vs.ssw[i].max = Math.max(vs.ssw[i].max, v);
        vs.ssw[i].sum += v; vs.ssw[i].cnt++;
        sSum += v; sOn++;
    }
    sswV.push({name:d.name, now:v, min:vs.ssw[i].cnt>0?vs.ssw[i].min:0, max:vs.ssw[i].max, avg:vs.ssw[i].cnt>0?(vs.ssw[i].sum/vs.ssw[i].cnt).toFixed(1):0, alarm:v>480||(v<400&&v>0), deviation:0});
});

if (sOn >= 2) {
    const avgV = sSum/sOn;
    sswV.forEach(s => { s.deviation = avgV>0 ? (Math.abs(s.now-avgV)/avgV*100).toFixed(1) : 0; s.imbalance = s.deviation > 5; });
}

flow.set('vStats', vs);
msg.voltage = {cfwVoltage:cfwV, sswVoltage:sswV};
return msg;

const cfw = flow.get('cfwDevices') || [];
const ssw = flow.get('sswDevices') || [];
const now = new Date();
const ts = now.toISOString().replace('T',' ').substring(0,19);

let line = ts;
cfw.forEach(d => {
    line += ',' + d.current + ',' + d.frequency + ',' + d.dcBusVoltage + ',' + d.torque + ',' + d.speedRPM + ',' + d.statusText + ',' + d.faultCode;
});
ssw.forEach(d => {
    line += ',' + d.current + ',' + d.voltage + ',' + d.power + ',' + d.statusText + ',' + d.faultCode;
});

msg.payload = line + '\n';
return msg;

const d = flow.get('cfwDevices') || [];
const points = [];
d.forEach((dev,i) => {
    points.push({
        measurement: 'cfw900',
        tags: {device: 'CFW900_'+(i+1)},
        fields: {
            current: dev.current,
            frequency: dev.frequency,
            dc_bus_voltage: dev.dcBusVoltage,
            torque: dev.torque,
            speed_rpm: dev.speedRPM,
            is_running: dev.running?1:0,
            is_fault: dev.fault?1:0,
            fault_code: dev.faultCode
        },
        timestamp: Date.now()
    });
});
msg.payload = points;
return msg;

const d = flow.get('sswDevices') || [];
const points = [];
d.forEach((dev,i) => {
    points.push({
        measurement: 'ssw900',
        tags: {device: 'SSW900_'+(i+1)},
        fields: {
            current: dev.current,
            voltage: dev.voltage,
            power: dev.power,
            is_running: dev.running?1:0,
            is_fault: dev.fault?1:0,
            fault_code: dev.faultCode
        },
        timestamp: Date.now()
    });
});
msg.payload = points;
return msg;
